import Anthropic from "@anthropic-ai/sdk";

export interface AnthropicEnv {
  ANTHROPIC_API_KEY: string;
}

// The @anthropic-ai/sdk uses the global fetch and runs on Workers. Create the
// client per request from the binding.
export function createAnthropic(env: AnthropicEnv) {
  return new Anthropic({ apiKey: env.ANTHROPIC_API_KEY });
}
